    n->unit_type = unit->type;
    unit->entity->is_collidable = 1;
    n->unit_x = unit->entity->x;
    n->unit_y = unit->entity->y;
    n->grid_anchor_x = unit->mobd_anchors.grid->x;
    n->grid_anchor_y = unit->mobd_anchors.grid->y;
